export interface EnterpriseEvent<TPayload = unknown> {
  id: string;
  type: string;
  payload: TPayload;
  source: string;
  occurredAt: string;
  correlationId?: string;
  metadata?: Record<string, unknown>;
}

type EnterpriseEventHandler<TPayload = unknown> = (event: EnterpriseEvent<TPayload>) => void;

export interface EnterpriseEventBus {
  publish<TPayload = unknown>(event: Omit<EnterpriseEvent<TPayload>, "id" | "occurredAt">): EnterpriseEvent<TPayload>;
  subscribe<TPayload = unknown>(eventType: string, handler: EnterpriseEventHandler<TPayload>): () => void;
  listRecent(limit?: number): EnterpriseEvent[];
}

function createEventId(): string {
  const random = Math.random().toString(36).slice(2, 10);
  return `evt_${Date.now()}_${random}`;
}

export class InMemoryEnterpriseEventBus implements EnterpriseEventBus {
  private readonly handlers = new Map<string, Set<EnterpriseEventHandler>>();
  private readonly records: EnterpriseEvent[] = [];

  constructor(private readonly maxRecords = 5000) {}

  publish<TPayload = unknown>(event: Omit<EnterpriseEvent<TPayload>, "id" | "occurredAt">): EnterpriseEvent<TPayload> {
    const fullEvent: EnterpriseEvent<TPayload> = {
      id: createEventId(),
      occurredAt: new Date().toISOString(),
      ...event,
    };

    this.records.unshift(fullEvent);
    if (this.records.length > this.maxRecords) {
      this.records.length = this.maxRecords;
    }

    const allHandlers = this.handlers.get('*');
    const typeHandlers = this.handlers.get(fullEvent.type);

    allHandlers?.forEach((handler) => handler(fullEvent));
    typeHandlers?.forEach((handler) => handler(fullEvent));

    return fullEvent;
  }

  subscribe<TPayload = unknown>(eventType: string, handler: EnterpriseEventHandler<TPayload>): () => void {
    const current = this.handlers.get(eventType) ?? new Set<EnterpriseEventHandler>();
    current.add(handler as EnterpriseEventHandler);
    this.handlers.set(eventType, current);

    return () => {
      const set = this.handlers.get(eventType);
      if (!set) {
        return;
      }

      set.delete(handler as EnterpriseEventHandler);
      if (set.size === 0) {
        this.handlers.delete(eventType);
      }
    };
  }

  listRecent(limit = 100): EnterpriseEvent[] {
    return this.records.slice(0, Math.max(0, limit));
  }
}
