export type DynamicConfigValue = string | number | boolean | null | Record<string, unknown> | unknown[];

type DynamicConfigListener = (key: string, value: DynamicConfigValue) => void;

export interface DynamicConfigStore {
  get<TValue extends DynamicConfigValue = DynamicConfigValue>(key: string): TValue | undefined;
  set<TValue extends DynamicConfigValue = DynamicConfigValue>(key: string, value: TValue): void;
  unset(key: string): void;
  snapshot(): Record<string, DynamicConfigValue>;
  subscribe(listener: DynamicConfigListener): () => void;
}

export class InMemoryDynamicConfigStore implements DynamicConfigStore {
  private readonly values = new Map<string, DynamicConfigValue>();
  private readonly listeners = new Set<DynamicConfigListener>();

  constructor(seed?: Record<string, DynamicConfigValue>) {
    if (!seed) {
      return;
    }

    Object.entries(seed).forEach(([key, value]) => {
      this.values.set(key, value);
    });
  }

  get<TValue extends DynamicConfigValue = DynamicConfigValue>(key: string): TValue | undefined {
    return this.values.get(key) as TValue | undefined;
  }

  set<TValue extends DynamicConfigValue = DynamicConfigValue>(key: string, value: TValue): void {
    this.values.set(key, value);
    this.listeners.forEach((listener) => listener(key, value));
  }

  unset(key: string): void {
    this.values.delete(key);
    this.listeners.forEach((listener) => listener(key, null));
  }

  snapshot(): Record<string, DynamicConfigValue> {
    return Object.fromEntries(this.values.entries());
  }

  subscribe(listener: DynamicConfigListener): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }
}
