import type { DynamicConfigStore } from "./dynamic-config";

export interface FeatureFlagDefinition {
  key: string;
  description: string;
  defaultValue: boolean;
}

export interface FeatureFlagManager {
  define(flag: FeatureFlagDefinition): void;
  isEnabled(key: string): boolean;
  list(): FeatureFlagDefinition[];
}

export class ConfigBackedFeatureFlagManager implements FeatureFlagManager {
  private readonly definitions = new Map<string, FeatureFlagDefinition>();

  constructor(private readonly dynamicConfig: DynamicConfigStore) {}

  define(flag: FeatureFlagDefinition): void {
    this.definitions.set(flag.key, flag);
    const current = this.dynamicConfig.get<boolean>(`feature.${flag.key}`);
    if (typeof current === 'undefined') {
      this.dynamicConfig.set(`feature.${flag.key}`, flag.defaultValue);
    }
  }

  isEnabled(key: string): boolean {
    const def = this.definitions.get(key);
    if (!def) {
      return false;
    }

    const value = this.dynamicConfig.get<boolean>(`feature.${key}`);
    return typeof value === 'boolean' ? value : def.defaultValue;
  }

  list(): FeatureFlagDefinition[] {
    return Array.from(this.definitions.values());
  }
}
