export type HealthStatus = "healthy" | "degraded" | "down";

export interface HealthCheckResult {
  module: string;
  status: HealthStatus;
  checkedAt: string;
  details?: Record<string, unknown>;
}

export interface HealthManager {
  register(module: string, check: () => Promise<HealthCheckResult> | HealthCheckResult): void;
  check(module: string): Promise<HealthCheckResult>;
  checkAll(): Promise<HealthCheckResult[]>;
}

export class InMemoryHealthManager implements HealthManager {
  private readonly checks = new Map<string, () => Promise<HealthCheckResult> | HealthCheckResult>();

  register(module: string, check: () => Promise<HealthCheckResult> | HealthCheckResult): void {
    this.checks.set(module, check);
  }

  async check(module: string): Promise<HealthCheckResult> {
    const check = this.checks.get(module);
    if (!check) {
      return {
        module,
        status: "down",
        checkedAt: new Date().toISOString(),
        details: {
          reason: "Health check not registered",
        },
      };
    }

    return Promise.resolve(check());
  }

  async checkAll(): Promise<HealthCheckResult[]> {
    const modules = Array.from(this.checks.keys());
    const checks = modules.map((module) => this.check(module));
    return Promise.all(checks);
  }
}
